use std::hash::{BuildHasher, Hasher};

#[repr(C)]
pub struct RandomState {
    k0: u64,
    k1: u64,
}

impl BuildHasher for RandomState {
    type Hasher = std::collections::hash_map::DefaultHasher;
    fn build_hasher(&self) -> Self::Hasher { unimplemented!() }
}

impl RandomState {
    fn hash_one(&self, x: &usize) -> u64 {
        let _ = self;
        let mut rax: std::collections::hash_map::DefaultHasher = std::collections::hash_map::DefaultHasher::new();
        rax.write_usize(*x);
        rax.finish()
    }
}

use std::collections::HashMap;

pub struct State {
    pub jt: HashMap<usize, usize>,
    pub tc: bool,
}

impl State {
    fn jump(&self, i: usize, fwd: bool) -> usize {
        if self.tc == fwd {
            return i;
        }
        *self.jt.get(&i).expect("no entry found for key")
    }
}
